package com.example.yourpackage;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.core.io.ResourceLoader;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;

@RestController
@RequestMapping("/api/profile-picture")
public class FileUploadController {
    private final ResourceLoader resourceLoader;

    @Autowired
    public FileUploadController(ResourceLoader resourceLoader) {
        this.resourceLoader = resourceLoader;
    }

    @PostMapping(value = "/upload", consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
    public ResponseEntity<String> uploadFile(@RequestParam("file") MultipartFile file) throws IOException {
        if (file.isEmpty()) {
            return ResponseEntity.badRequest().body("Please select a file to upload.");
        }
        String contentType = file.getContentType();
        // Add your validation logic for common image formats here.
        byte[] bytes = file.getBytes();
        String location = "images/" + file.getOriginalFilename();
        try {
            resourceLoader.getResource("classpath:" + location).createParentDirectories();
            resourceLoader.getResource("classpath:" + location).getFile().write(bytes);
        } catch (Exception e) {
            return ResponseEntity.internalServerError().body("Could not save file.");
        }
        return ResponseEntity.ok("Image uploaded successfully.");
    }

    @PostMapping("/download")
    public ResponseEntity<byte[]> downloadFile(@RequestParam String fileName) throws IOException {
        byte[] bytes = resourceLoader.getResource("classpath:images/" + fileName).getContentAsByteArray();
        return ResponseEntity.ok()
                .contentType(MediaType.parseMediaType(getContentTypeFromExtension(fileName)))
                .header(HttpHeaders.CONTENT_DISPOSITION, "attachment; filename=\"" + fileName + "\"")
                .body(bytes);
    }

    private String getContentTypeFromExtension(String extension) {
        if ("png".equalsIgnoreCase(extension)) {
            return MediaType.IMAGE_PNG_VALUE;
        } else if ("jpg".equalsIgnoreCase(extension) || "jpeg".equalsIgnoreCase(extension)) {
            return MediaType.IMAGE_JPEG_VALUE;
        } else if ("gif".equalsIgnoreCase(extension)) {
            return MediaType.IMAGE_GIF_VALUE;
        }
        throw new IllegalArgumentException("Unsupported image format: " + extension);
    }
}